import React, { useState } from 'react';

const VerifyCertificate = () => {
  const [certificateNumber, setCertificateNumber] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [verificationResult, setVerificationResult] = useState(null);
  
  const handleInputChange = (e) => {
    setCertificateNumber(e.target.value);
  };
  
  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!certificateNumber.trim()) {
      setError('Please enter a certificate number');
      return;
    }
    
    setLoading(true);
    setError(null);
    setVerificationResult(null);
    
    try {
      const response = await fetch('/api/certificates/verify', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ certificateNumber: certificateNumber.trim() })
      });
      
      const data = await response.json();
      
      if (!response.ok) {
        throw new Error(data.message || 'Verification failed');
      }
      
      setVerificationResult(data);
    } catch (err) {
      console.error('Certificate verification error:', err);
      setError(err.message || 'An error occurred during verification');
    } finally {
      setLoading(false);
    }
  };
  
  const formatDate = (dateString) => {
    if (!dateString) return 'N/A';
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric'
    });
  };
  
  const getCertificateTypeDisplay = (type) => {
    const typeMap = {
      'bachelor': 'Bachelor\'s Degree',
      'master': 'Master\'s Degree',
      'phd': 'Doctoral Degree',
      'professional': 'Professional Certificate'
    };
    
    return typeMap[type] || type;
  };
  
  return (
    <div className="min-h-screen bg-gray-100 py-12 px-4 sm:px-6 lg:px-8">
      <div className="max-w-3xl mx-auto">
        <div className="text-center mb-10">
          <h1 className="text-3xl font-bold text-blue-900">Certificate Verification</h1>
          <p className="mt-2 text-gray-600">
            Verify the authenticity of a Global Horizon University certificate
          </p>
        </div>
        
        <div className="bg-white shadow-md rounded-lg overflow-hidden">
          <div className="px-4 py-5 sm:px-6 bg-blue-900 text-white">
            <h2 className="text-xl font-semibold">Verify Certificate</h2>
            <p className="mt-1 text-sm">Enter the certificate number to verify its authenticity</p>
          </div>
          
          <div className="p-6">
            <form onSubmit={handleSubmit}>
              <div className="mb-6">
                <label htmlFor="certificateNumber" className="block text-sm font-medium text-gray-700 mb-2">
                  Certificate Number
                </label>
                <div className="mt-1 flex rounded-md shadow-sm">
                  <input
                    type="text"
                    name="certificateNumber"
                    id="certificateNumber"
                    className="focus:ring-blue-500 focus:border-blue-500 flex-1 block w-full rounded-md sm:text-sm border-gray-300"
                    placeholder="e.g. GHU-BA-2023-123456"
                    value={certificateNumber}
                    onChange={handleInputChange}
                  />
                  <button
                    type="submit"
                    disabled={loading}
                    className={`ml-3 inline-flex items-center px-4 py-2 border border-transparent text-sm font-medium rounded-md shadow-sm text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 ${
                      loading ? 'opacity-70 cursor-not-allowed' : ''
                    }`}
                  >
                    {loading ? 'Verifying...' : 'Verify'}
                  </button>
                </div>
                <p className="mt-2 text-sm text-gray-500">
                  Enter the certificate number exactly as it appears on the certificate
                </p>
              </div>
            </form>
            
            {error && (
              <div className="mb-6 bg-red-50 border border-red-200 rounded-md p-4 text-red-800">
                <div className="flex">
                  <div className="flex-shrink-0">
                    <svg className="h-5 w-5 text-red-400" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor">
                      <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
                    </svg>
                  </div>
                  <div className="ml-3">
                    <h3 className="text-sm font-medium text-red-800">Verification failed</h3>
                    <div className="mt-2 text-sm text-red-700">
                      <p>{error}</p>
                    </div>
                  </div>
                </div>
              </div>
            )}
            
            {verificationResult && verificationResult.success && (
              <div className="bg-green-50 border border-green-200 rounded-md p-6">
                <div className="flex items-center mb-4">
                  <svg className="h-6 w-6 text-green-600 mr-2" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor">
                    <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
                  </svg>
                  <h3 className="text-lg font-medium text-green-800">Certificate Verified</h3>
                </div>
                
                <div className="border-t border-green-200 pt-4">
                  <dl className="grid grid-cols-1 gap-x-4 gap-y-6 sm:grid-cols-2">
                    <div className="sm:col-span-1">
                      <dt className="text-sm font-medium text-gray-500">Certificate Number</dt>
                      <dd className="mt-1 text-sm text-gray-900">{verificationResult.data.certificateNumber}</dd>
                    </div>
                    <div className="sm:col-span-1">
                      <dt className="text-sm font-medium text-gray-500">Recipient</dt>
                      <dd className="mt-1 text-sm text-gray-900">{verificationResult.data.recipient}</dd>
                    </div>
                    <div className="sm:col-span-1">
                      <dt className="text-sm font-medium text-gray-500">Program</dt>
                      <dd className="mt-1 text-sm text-gray-900">{verificationResult.data.program}</dd>
                    </div>
                    <div className="sm:col-span-1">
                      <dt className="text-sm font-medium text-gray-500">Certificate Type</dt>
                      <dd className="mt-1 text-sm text-gray-900">{getCertificateTypeDisplay(verificationResult.data.certificateType)}</dd>
                    </div>
                    <div className="sm:col-span-1">
                      <dt className="text-sm font-medium text-gray-500">Issue Date</dt>
                      <dd className="mt-1 text-sm text-gray-900">{formatDate(verificationResult.data.issueDate)}</dd>
                    </div>
                    <div className="sm:col-span-1">
                      <dt className="text-sm font-medium text-gray-500">Status</dt>
                      <dd className="mt-1 text-sm text-gray-900">
                        <span className="px-2 inline-flex text-xs leading-5 font-semibold rounded-full bg-green-100 text-green-800">
                          {verificationResult.data.status.charAt(0).toUpperCase() + verificationResult.data.status.slice(1)}
                        </span>
                      </dd>
                    </div>
                  </dl>
                </div>
                
                <div className="mt-6 border-t border-green-200 pt-4">
                  <p className="text-sm text-gray-600">
                    This certificate has been verified as authentic and was issued by Global Horizon University.
                  </p>
                </div>
              </div>
            )}
          </div>
        </div>
        
        <div className="mt-8 bg-white shadow-md rounded-lg overflow-hidden">
          <div className="px-4 py-5 sm:px-6 bg-gray-50">
            <h2 className="text-lg font-medium text-gray-900">About Certificate Verification</h2>
          </div>
          <div className="px-4 py-5 sm:p-6">
            <div className="prose max-w-none text-gray-700">
              <p>
                Global Horizon University provides this verification service to confirm the authenticity of our academic certificates. 
                Each certificate issued by our institution contains a unique certificate number that can be verified through this system.
              </p>
              <h3>How to Verify a Certificate</h3>
              <ol>
                <li>Locate the certificate number on the document (format: GHU-XX-YYYY-NNNNNN)</li>
                <li>Enter the complete certificate number in the verification field above</li>
                <li>Click the "Verify" button to check the certificate's authenticity</li>
              </ol>
              <p>
                If you have any questions or concerns about the verification process, please contact our registrar's office at 
                <a href="mailto:registrar@globalhorizonuniversity.edu" className="text-blue-600 hover:text-blue-800"> registrar@globalhorizonuniversity.edu</a>.
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default VerifyCertificate;
